'use strict';

// MODULES //

var tape = require( 'tape' );
var Complex64 = require( '@stdlib/complex/float32/ctor' );
var Complex128 = require( '@stdlib/complex/float64/ctor' );
var defaults = require( '@stdlib/ndarray/defaults' );
var scalarDataType = require( './../lib' );


// VARIABLES //

var DEFAULT_REAL = defaults.get( 'dtypes.real_floating_point' );
var DEFAULT_CMPLX = defaults.get( 'dtypes.complex_floating_point' );
var DEFAULT_BOOL = defaults.get( 'dtypes.boolean' );


// TESTS //

tape( 'main export is a function', function test( t ) {
	t.ok( true, __filename );
	t.strictEqual( typeof scalarDataType, 'function', 'main export is a function' );
	t.end();
});

tape( 'the function returns the default real-valued floating-point data type for numbers', function test( t ) {
	t.strictEqual( scalarDataType( 3.14 ), DEFAULT_REAL, 'returns expected value' );
	t.strictEqual( scalarDataType( 0 ), DEFAULT_REAL, 'returns expected value' );
	t.strictEqual( scalarDataType( -1 ), DEFAULT_REAL, 'returns expected value' );
	t.end();
});

tape( 'the function returns the default boolean data type for booleans', function test( t ) {
	t.strictEqual( scalarDataType( true ), DEFAULT_BOOL, 'returns expected value' );
	t.strictEqual( scalarDataType( false ), DEFAULT_BOOL, 'returns expected value' );
	t.end();
});

tape( 'the function returns a corresponding complex data type for complex-like values of a known complex data type', function test( t ) {
	t.strictEqual( scalarDataType( new Complex64( 1.0, 2.0 ) ), 'complex64', 'returns expected value' );
	t.strictEqual( scalarDataType( new Complex128( 1.0, 2.0 ) ), 'complex128', 'returns expected value' );
	t.end();
});

tape( 'the function returns the default complex-valued floating-point data type for complex-like values of an unknown complex data type', function test( t ) {
	var v = {
		're': 1.0,
		'im': 2.0
	};
	t.strictEqual( scalarDataType( v ), DEFAULT_CMPLX, 'returns expected value' );
	t.end();
});

tape( 'the function returns "generic" for any other value', function test( t ) {
	var values;
	var i;

	values = [
		'beep',
		[ 1, 2, 3 ],
		{},
		null,
		void 0,
		function noop() {}
	];
	for ( i = 0; i < values.length; i++ ) {
		t.strictEqual( scalarDataType( values[ i ] ), 'generic', 'returns expected value for '+JSON.stringify( values[ i ] ) );
	}
	t.end();
});
